    validateRequired
};

import db from '../config/db.js';

const useSupabase = (process.env.DB_MODE || 'postgres').toLowerCase() === 'supabase';

function toMillis(value) {
    if (!value) return null;
    const t = new Date(value).getTime();
    return Number.isNaN(t) ? null : t;
}

function averageHours(durationsMs) {
    if (!durationsMs.length) return null;
    const sum = durationsMs.reduce((acc, v) => acc + v, 0);
    return sum / durationsMs.length / 3600000;
}

function buildMetrics(rows) {
    const mttrSamples = [];
    const ticketsByActivo = new Map();

    for (const row of rows) {
        const inicio = toMillis(row.fecha_inicio);
        const fin = toMillis(row.fecha_fin);
        if (inicio !== null && fin !== null && fin >= inicio) {
            mttrSamples.push(fin - inicio);
        }

        const creado = toMillis(row.fecha_creacion);
        if (creado !== null && row.id_activo !== null && row.id_activo !== undefined) {
            const list = ticketsByActivo.get(row.id_activo) || [];
            list.push(creado);
            ticketsByActivo.set(row.id_activo, list);
        }
    }

    const mtbfSamples = [];
    for (const times of ticketsByActivo.values()) {
        if (times.length < 2) continue;
        times.sort((a, b) => a - b);
        for (let i = 1; i < times.length; i += 1) {
            const diff = times[i] - times[i - 1];
            if (diff >= 0) mtbfSamples.push(diff);
        }
    }

    return {
        mttr_hours: averageHours(mttrSamples),
        mtbf_hours: averageHours(mtbfSamples),
        mttr_samples: mttrSamples.length,
        mtbf_samples: mtbfSamples.length
    };
}

class MetricsModel {
    async getOperationalMetrics() {
        if (useSupabase) {
            const { data, error } = await db.supabase
                .from('tickets')
                .select('id_activo, fecha_creacion, ordenes_mantenimiento(fecha_inicio, fecha_fin)');
            if (error) throw error;

            const rows = (data || []).map((row) => ({
                id_activo: row.id_activo,
                fecha_creacion: row.fecha_creacion,
                fecha_inicio: row.ordenes_mantenimiento?.fecha_inicio || null,
                fecha_fin: row.ordenes_mantenimiento?.fecha_fin || null
            }));

            return buildMetrics(rows);
        }

        const { rows } = await db.query(
            `SELECT
                t.id_activo,
                t.fecha_creacion,
                om.fecha_inicio,
                om.fecha_fin
             FROM tickets t
             LEFT JOIN ordenes_mantenimiento om ON om.id_ticket = t.id_ticket`
        );

        return buildMetrics(rows);
    }
}

export default MetricsModel;

import test from 'node:test';
import assert from 'node:assert/strict';
import assetRouter from '../src/routes/asset.routes.js';

function hasRoute(path, method) {
    return assetRouter.stack.some(
        (l) => l.route && l.route.path === path && l.route.methods?.[method]
    );
}

test('Asset routes exponen CRUD basico', async () => {
    assert.ok(hasRoute('/', 'get'));
    assert.ok(hasRoute('/', 'post'));
    assert.ok(hasRoute('/:id', 'get'));
    assert.ok(hasRoute('/:id', 'put'));
    assert.ok(hasRoute('/:id', 'delete'));
});

import test from 'node:test';
import assert from 'node:assert/strict';
import fs from 'node:fs';
import path from 'node:path';

const schemaPath = path.resolve('./sql/01_schema.sql');
const schema = fs.readFileSync(schemaPath, 'utf8');

test('Schema define tablas principales con PK, FK y constraints', async () => {
    const requiredTables = [
        'USUARIOS',
        'UBICACIONES',
        'CATEGORIAS',
        'PROVEEDORES',
        'SOFTWARE',
        'REPUESTOS',
        'ACTIVOS',
        'LICENCIAS',
        'TICKETS',
        'HISTORIAL_ACTIVOS',
        'BAJAS_ACTIVOS',
        'ASIGNACION_LICENCIAS',
        'CATALOGO_PRECIOS_PROVEEDORES',
        'ORDENES_MANTENIMIENTO',
        'CONSUMO_REPUESTOS',
        'ALERTAS'
    ];

    for (const table of requiredTables) {
        assert.match(
            schema,
            new RegExp(`CREATE TABLE IF NOT EXISTS\\s+${table}\\s*\\(`, 'i'),
            `Falta tabla ${table}`
        );
    }

    assert.match(schema, /PRIMARY KEY/i);
    assert.match(schema, /REFERENCES/i);
    assert.match(schema, /NOT NULL/i);
    assert.match(schema, /UNIQUE/i);
});

test('Schema agrega indice para busqueda por serial', async () => {
    assert.match(schema, /idx_activos_serial_lower/i);
    assert.match(schema, /CREATE INDEX IF NOT EXISTS idx_activos_serial_lower ON ACTIVOS/i);
});

test('Schema marca serial como UNIQUE en activos', async () => {
    assert.match(schema, /serial\s+VARCHAR\(100\)\s+UNIQUE\s+NOT NULL/i);
});

